"""Streamlit landing page for the Telco Customer Churn portfolio dashboard."""

from __future__ import annotations

import json
from pathlib import Path

import streamlit as st

from src.data import clean_data, load_raw_data

PROJECT_ROOT = Path(__file__).resolve().parent

st.set_page_config(
    page_title="Telco Customer Churn",
    page_icon="📊",
    layout="wide",
)


@st.cache_data
def get_clean_data():
    """Load the cleaned dataset once per Streamlit session."""
    return clean_data(load_raw_data())


@st.cache_data
def get_metrics():
    """Load model metrics generated by the training script."""
    metrics_path = PROJECT_ROOT / "artifacts" / "metrics.json"
    if not metrics_path.exists():
        return {}
    return json.loads(metrics_path.read_text(encoding="utf-8"))


data = get_clean_data()
metrics = get_metrics()
churn_rate = (data["Churn"] == "Yes").mean()

st.title("Telco Customer Churn Dashboard")
st.caption("Portfolio dashboard | Bảng điều khiển dự đoán khách hàng rời bỏ dịch vụ")

st.markdown(
    """
This project turns a complete churn analysis notebook into a reproducible machine
learning demo. Explore the data, compare three models, then estimate churn risk for
one customer or an uploaded CSV file.

Dự án chuyển notebook phân tích churn thành demo machine learning có thể tái lập.
Bạn có thể khám phá dữ liệu, so sánh ba mô hình và dự đoán rủi ro cho từng khách hàng
hoặc một tệp CSV.
"""
)

col1, col2, col3, col4 = st.columns(4)
col1.metric("Customers | Khách hàng", f"{len(data):,}")
col2.metric("Churn rate | Tỷ lệ churn", f"{churn_rate:.1%}")
col3.metric("Average tenure | Thâm niên TB", f"{data['tenure'].mean():.1f} months")
col4.metric(
    "Average monthly charges | Phí TB",
    f"${data['MonthlyCharges'].mean():.2f}",
)

st.subheader("Recommended model | Mô hình khuyến nghị")
st.markdown(
    """
**Logistic Regression** is the default deployment model. It has the strongest
validation F1, AUC and recall in the reproducible 60:40 evaluation while remaining
fast and interpretable. The prediction page also lets you compare it with SVM RBF
and Naive Bayes.
"""
)

if metrics:
    metric_rows = [
        {
            "Model": values["display_name"],
            "F1": values["f1"],
            "AUC": values["auc"],
            "Recall": values["recall"],
        }
        for values in metrics.values()
    ]
    st.dataframe(metric_rows, use_container_width=True, hide_index=True)

st.info(
    "Use the pages in the sidebar: EDA, Model Comparison, and Prediction. "
    "| Chọn các trang bên trái để xem EDA, so sánh mô hình và dự đoán."
)
